// TestBatchEvaluationSuccess tests batch evaluation of multiple flags
func TestBatchEvaluationSuccess(t *testing.T) {
	logger, _ := zap.NewDevelopment()

	store := &MockStorer{
		flags: map[string]*flipt.Flag{
			"boolean_flag": {
				Key:     "boolean_flag",
				Name:    "Boolean Flag",
				Type:    flipt.FlagType_BOOLEAN_FLAG_TYPE,
				Enabled: true,
			},
			"variant_flag": {
				Key:     "variant_flag",
				Name:    "Variant Flag",
				Type:    flipt.FlagType_VARIANT_FLAG_TYPE,
				Enabled: true,
				Variants: []*flipt.Variant{
					{
						Key:        "variant_a",
						Name:       "Variant A",
						Attachment: `{"color":"red"}`,
					},
				},
			},
		},
		rollouts: map[string][]*storage.EvaluationRollout{},
	}

	server := evaluation.New(logger, store)

	batchReq := &rpcevaluation.BatchEvaluationRequest{
		RequestId: "batch-req-123",
		Requests: []*rpcevaluation.EvaluationRequest{
			{
				RequestId:    "req-1",
				NamespaceKey: "default",
				FlagKey:      "boolean_flag",
				EntityId:     "user-1",
				Context:      map[string]string{},
			},
			{
				RequestId:    "req-2",
				NamespaceKey: "default",
				FlagKey:      "variant_flag",
				EntityId:     "user-1",
				Context:      map[string]string{},
			},
		},
	}

	resp, err := server.Batch(context.Background(), batchReq)
	if err != nil {
		t.Fatal("Batch evaluation failed:", err)
	}

	if len(resp.Responses) != 2 {
		t.Error("Expected 2 responses in batch, got", len(resp.Responses))
	}

	if resp.Responses[0].Type != rpcevaluation.EvaluationResponseType_BOOLEAN_EVALUATION_RESPONSE_TYPE {
		t.Error("Expected first response to be boolean type")
	}

	if resp.Responses[1].Type != rpcevaluation.EvaluationResponseType_VARIANT_EVALUATION_RESPONSE_TYPE {
		t.Error("Expected second response to be variant type")
	}
}

// TestBatchEvaluationWithFlagNotFound tests batch evaluation when one flag is not found
func TestBatchEvaluationWithFlagNotFound(t *testing.T) {
	logger, _ := zap.NewDevelopment()

	store := &MockStorer{
		flags: map[string]*flipt.Flag{
			"existing_flag": {
				Key:     "existing_flag",
				Name:    "Existing Flag",
				Type:    flipt.FlagType_BOOLEAN_FLAG_TYPE,
				Enabled: true,
			},
		},
		rollouts: map[string][]*storage.EvaluationRollout{},
	}

	server := evaluation.New(logger, store)

	batchReq := &rpcevaluation.BatchEvaluationRequest{
		RequestId: "batch-req-not-found",
		Requests: []*rpcevaluation.EvaluationRequest{
			{
				RequestId:    "req-1",
				NamespaceKey: "default",
				FlagKey:      "existing_flag",
				EntityId:     "user-1",
				Context:      map[string]string{},
			},
			{
				RequestId:    "req-2",
				NamespaceKey: "default",
				FlagKey:      "nonexistent_flag",
				EntityId:     "user-1",
				Context:      map[string]string{},
			},
		},
	}

	resp, err := server.Batch(context.Background(), batchReq)
	if err != nil {
		t.Fatal("Batch evaluation failed:", err)
	}

	if len(resp.Responses) != 2 {
		t.Error("Expected 2 responses in batch, got", len(resp.Responses))
	}

	// First response should be boolean
	if resp.Responses[0].Type != rpcevaluation.EvaluationResponseType_BOOLEAN_EVALUATION_RESPONSE_TYPE {
		t.Error("Expected first response to be boolean type")
	}

	// Second response should be error (flag not found)
	if resp.Responses[1].Type != rpcevaluation.EvaluationResponseType_ERROR_EVALUATION_RESPONSE_TYPE {
		t.Error("Expected second response to be error type for missing flag")
	}

	// Verify error details
	errorResp := resp.Responses[1].GetErrorResponse()
	if errorResp == nil {
		t.Fatal("Expected error response, got nil")
	}

	if errorResp.Reason != rpcevaluation.ErrorEvaluationReason_NOT_FOUND_ERROR_EVALUATION_REASON {
		t.Error("Expected NOT_FOUND error reason")
	}
}

