// TestRESTAPIBooleanEndpoint tests the REST API /evaluate/v1/boolean endpoint
func TestRESTAPIBooleanEndpoint(t *testing.T) {
	logger, _ := zap.NewDevelopment()

	store := &MockStorer{
		flags: map[string]*flipt.Flag{
			"rest_boolean_flag": {
				Key:     "rest_boolean_flag",
				Name:    "REST Boolean Flag",
				Type:    flipt.FlagType_BOOLEAN_FLAG_TYPE,
				Enabled: true,
			},
		},
		rollouts: map[string][]*storage.EvaluationRollout{},
	}

	server := evaluation.New(logger, store)

	// Create a mock HTTP handler that uses the evaluation server
	handler := http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		if r.Method != http.MethodPost {
			w.WriteHeader(http.StatusMethodNotAllowed)
			return
		}

		var req rpcevaluation.EvaluationRequest
		body, _ := io.ReadAll(r.Body)
		if err := json.Unmarshal(body, &req); err != nil {
			w.WriteHeader(http.StatusBadRequest)
			w.Write([]byte(`{"error":"invalid request body"}`))
			return
		}

		resp, err := server.Boolean(context.Background(), &req)
		if err != nil {
			w.WriteHeader(http.StatusInternalServerError)
			w.Write([]byte(`{"error":"evaluation failed"}`))
			return
		}

		w.Header().Set("Content-Type", "application/json")
		data, _ := protojson.Marshal(resp)
		w.Write(data)
	})

	// Create test request
	reqBody := rpcevaluation.EvaluationRequest{
		RequestId:    "rest-req-1",
		NamespaceKey: "default",
		FlagKey:      "rest_boolean_flag",
		EntityId:     "user-1",
		Context:      map[string]string{},
	}

	bodyBytes, _ := json.Marshal(reqBody)
	httpReq := httptest.NewRequest(http.MethodPost, "/evaluate/v1/boolean", bytes.NewReader(bodyBytes))
	w := httptest.NewRecorder()

	handler.ServeHTTP(w, httpReq)

	if w.Code != http.StatusOK {
		t.Fatalf("Expected status 200, got %d", w.Code)
	}

	var respBody rpcevaluation.BooleanEvaluationResponse
	if err := json.Unmarshal(w.Body.Bytes(), &respBody); err != nil {
		t.Fatal("Failed to unmarshal response:", err)
	}

	if !respBody.Enabled {
		t.Error("Expected enabled to be true")
	}
}

